Simplifica este código Kotlin que tiene clases innecesarias y código duplicado. Aplica YAGNI y KISS.

```kotlin
interface Entity<T> {
    fun getId(): String
    fun copy(): T
}

interface Validatable {
    fun validate(): Boolean
}

interface Serializable {
    fun toJson(): String
}

abstract class BaseEntity : Entity<BaseEntity>, Validatable, Serializable {
    abstract override fun getId(): String
    abstract override fun validate(): Boolean

    override fun copy(): BaseEntity {
        throw NotImplementedError()
    }

    override fun toJson(): String {
        return "{}"
    }
}

class UserEntity(
    private val id: String,
    private val name: String,
    private val email: String
) : BaseEntity() {

    override fun getId(): String = id

    override fun validate(): Boolean {
        return name.isNotBlank() && email.contains("@")
    }

    fun getName(): String = name
    fun getEmail(): String = email
}

class ProductEntity(
    private val id: String,
    private val title: String,
    private val price: Double
) : BaseEntity() {

    override fun getId(): String = id

    override fun validate(): Boolean {
        return title.isNotBlank() && price > 0
    }

    fun getTitle(): String = title
    fun getPrice(): Double = price
}

fun validateEmail(email: String): Boolean {
    return email.contains("@") && email.contains(".")
}

fun validateUserEmail(user: UserEntity): Boolean {
    return user.getEmail().contains("@") && user.getEmail().contains(".")
}
