Simplifica este código TypeScript que tiene una arquitectura de fábricas abstractas excesivamente compleja para solo 2 tipos de notificaciones. Aplica KISS y YAGNI - recuerda que no necesitamos abstracciones para 2 casos.

```typescript
// Abstract Factory Pattern para solo 2 tipos de notificaciones
abstract class NotificationFactory {
  abstract createSender(): NotificationSender;
  abstract createFormatter(): NotificationFormatter;
  abstract createLogger(): NotificationLogger;
}

interface NotificationSender {
  send(to: string, message: string): Promise<void>;
}

interface NotificationFormatter {
  format(content: string): string;
}

interface NotificationLogger {
  log(notification: Notification): void;
}

interface Notification {
  to: string;
  content: string;
  timestamp: Date;
}

// Email Factory
class EmailNotificationFactory extends NotificationFactory {
  createSender(): NotificationSender {
    return new EmailSender();
  }
  createFormatter(): NotificationFormatter {
    return new EmailFormatter();
  }
  createLogger(): NotificationLogger {
    return new NotificationLoggerImpl();
  }
}

// SMS Factory
class SMSNotificationFactory extends NotificationFactory {
  createSender(): NotificationSender {
    return new SMSSender();
  }
  createFormatter(): NotificationFormatter {
    return new SMSFormatter();
  }
  createLogger(): NotificationLogger {
    return new NotificationLoggerImpl();
  }
}

// Implementaciones Email
class EmailSender implements NotificationSender {
  async send(to: string, message: string): Promise<void> {
    console.log(`Sending email to ${to}: ${message}`);
  }
}

class EmailFormatter implements NotificationFormatter {
  format(content: string): string {
    return `[EMAIL] ${content}`;
  }
}

// Implementaciones SMS
class SMSSender implements NotificationSender {
  async send(to: string, message: string): Promise<void> {
    console.log(`Sending SMS to ${to}: ${message}`);
  }
}

class SMSFormatter implements NotificationFormatter {
  format(content: string): string {
    return content.substring(0, 160); // SMS limit
  }
}

// Logger compartido
class NotificationLoggerImpl implements NotificationLogger {
  log(notification: Notification): void {
    console.log(`[${notification.timestamp}] To: ${notification.to}`);
  }
}

// Cliente
class NotificationService {
  private factory: NotificationFactory;

  constructor(factory: NotificationFactory) {
    this.factory = factory;
  }

  async notify(to: string, content: string): Promise<void> {
    const formatter = this.factory.createFormatter();
    const sender = this.factory.createSender();
    const logger = this.factory.createLogger();

    const formatted = formatter.format(content);
    await sender.send(to, formatted);
    logger.log({ to, content: formatted, timestamp: new Date() });
  }
}

// Uso
const emailService = new NotificationService(new EmailNotificationFactory());
const smsService = new NotificationService(new SMSNotificationFactory());
```
